const output = [];

for (const item of items) {
  for (const binaryKey of Object.keys(item.binary)) {

    // 1. Get lowercase filename for easier matching
    const fileName = item.binary[binaryKey].fileName.toLowerCase();

    // 2. Define CV-specific keywords
    const cvKeywords = ['cv', 'resume', 'vitae', 'bio', 'profile'];

    // 3. Check if it's a CV
    const isCV = cvKeywords.some(word => fileName.includes(word));

    output.push({
      json: {
        binaryKey,
        // 4. Set type to 'cv' if matched, otherwise 'tor'
        documentType: isCV ? 'cv' : 'tor',
        fileName: item.binary[binaryKey].fileName
      },
      binary: {
        [binaryKey]: item.binary[binaryKey]
      }
    });
  }
}

return output;

